package com.establo.controller;import com.establo.repository.*;import com.establo.service.NotificationService;import lombok.RequiredArgsConstructor;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/dashboard") @RequiredArgsConstructor public class DashboardController {private final HorseRepository horses;private final EmployeeRepository employees;private final ReservationRepository reservations;private final InventoryItemRepository inventory;private final NotificationService notifications;@GetMapping Map<String,Object> dashboard(){var alerts=notifications.all().stream().limit(5).map(n->Map.of("type",n.category(),"title",n.title(),"message",n.message())).toList();long low=inventory.findAll().stream().filter(i->i.isLowStock()).count();return Map.of("horses",horses.count(),"employees",employees.count(),"reservations",reservations.count(),"lowStock",low,"alerts",alerts,"unreadNotifications",notifications.unread());}}
